import React from 'react';
import styles from './MetricCards.module.css';

function fmt(v, dec = 1) {
  if (v == null || v === '') return '—';
  return typeof v === 'number' ? v.toFixed(dec) : v;
}

export default function MetricCards({ metrics, loading }) {
  const cards = [
    { 
      label: 'Roster Split', 
      value: metrics.totalPlayers ?? '—', 
      sub: `${metrics.forwards ?? 0} F · ${metrics.defensemen ?? 0} D · ${metrics.goalies ?? 0} G`, 
      color: 'accent' 
    },
    { 
      label: 'Forward Leaders', 
      value: metrics.topForwardScorer ?? '—', 
      sub: `Top F: ${metrics.maxForwardPts ?? 0} PTS avg`, 
      color: 'teal' 
    },
    { 
      label: 'Defense Impact', 
      value: metrics.topDefenseScorer ?? '—', 
      sub: `Top D: ${metrics.maxDefensePts ?? 0} PTS · ${metrics.avgDefenseBlks ?? 0} BLK`, 
      color: 'amber' 
    },
    { 
      label: 'Goalie GAA Avg', 
      value: fmt(metrics.avgGAA, 2), 
      sub: 'Goals Against Average', 
      color: 'blue' 
    },
    { 
      label: 'Goalie SV% Avg', 
      value: metrics.avgSVP != null ? fmt(metrics.avgSVP, 1) + '%' : '—', 
      sub: 'Save Percentage', 
      color: 'blue' 
    },
    { 
      label: 'Active Leagues', 
      value: metrics.leagueCount ?? '—', 
      sub: 'Total leagues in view', 
      color: 'accent' 
    },
  ];

  return (
    <div className={styles.grid}>
      {cards.map(c => (
        <div key={c.label} className={`${styles.card} ${styles[c.color]} ${loading ? styles.loading : ''}`}>
          <div className={styles.label}>{c.label}</div>
          <div className={styles.value}>{c.value}</div>
          <div className={styles.sub}>{c.sub}</div>
        </div>
      ))}
    </div>
  );
}
